\[
\begin{equation*}
a x+b y+c=0 \quad\left(a^{2}+b^{2}=1\right) \tag{1}
\end{equation*}
\]

\[
\begin{equation*}
d(x, y)=a x+b y+c \tag{2}
\end{equation*}
\]

\[
\begin{equation*}
\left\{(x, y) \mid d_{\min } \leqslant d(x, y) \leqslant d_{\max }\right\} \tag{3}
\end{equation*}
\]

\[
\begin{align*}
& d_{\min }=\min \left\{d_{0}, \ldots, d_{n}\right\} \\
& d_{\max }=\max \left\{d_{0}, \ldots, d_{n}\right\} \tag{4}
\end{align*}
\]

\[
\begin{equation*}
d(t)=2 t(1-t) d_{1} \tag{5}
\end{equation*}
\]

\[
\begin{align*}
& d_{\min }=\min \left\{0, \frac{d_{1}}{2}\right\} \\
& d_{\max }=\max \left\{0, \frac{d_{1}}{2}\right\} \tag{6}
\end{align*}
\]

\[
\begin{equation*}
d(t)=3 t(1-t)\left[(1-t) d_{1}+t d_{2}\right] \tag{7}
\end{equation*}
\]

\[
\begin{align*}
& d_{\min }=\min \left\{0, d\left(t_{1}\right)\right\} \\
& d_{\max }=\max \left\{0, d\left(t_{1}\right)\right\} \tag{9}
\end{align*}
\]

\[
\begin{align*}
& d_{\min }=\min \left\{d\left(t_{1}\right), d\left(t_{2}\right)\right\} \\
& d_{\max }=\max \left\{d\left(t_{1}\right), d\left(t_{2}\right)\right\} \tag{11}
\end{align*}
\]

\[
\begin{equation*}
\min \left\{0, d_{1}, d_{2}\right\} 3 t(1-t) \leqslant d(t) \leqslant \max \left\{0, d_{1}, d_{2}\right\} 3 t(1-t) \tag{12}
\end{equation*}
\]

\[
\begin{align*}
& d_{\min }=\frac{3}{4} \min \left\{0, d_{1}, d_{2}\right\} \\
& d_{\max }=\frac{3}{4} \max \left\{0, d_{1}, d_{2}\right\} \tag{13}
\end{align*}
\]

\[
\begin{equation*}
3 t(1-t)^{2} d_{1} \leqslant d(t) \leqslant 3 t^{2}(1-t) d_{2} \tag{14}
\end{equation*}
\]

\[
\begin{align*}
d_{\min } & =\frac{4}{9} \min \left\{0, d_{1}, d_{2}\right\} \\
d_{\max } & =\frac{4}{9} \max \left\{0, d_{1}, d_{2}\right\} \tag{15}
\end{align*}
\]

\[
\begin{equation*}
\mathbf{P}(t)=\sum_{i=0}^{n} \mathbf{P}_{i} B_{i}^{n}(t) \tag{16}
\end{equation*}
\]

\[
\begin{equation*}
a x+b y+c=0 \quad\left(a^{2}+b^{2}=1\right), \tag{17}
\end{equation*}
\]

\[
\begin{equation*}
d(t)=\sum_{i=0}^{n} d_{i} B_{i}^{n}(t), \quad d_{i}=a x_{i}+b y_{i}+c \tag{18}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{D}(t)=(t, d(t))=\sum_{i=0}^{n} \mathbf{D}_{i} B_{i}^{n}(t) \tag{19}
\end{equation*}
\]

