\[
\begin{equation*}
\mathbf{P}(t)=\frac{\sum_{i=0}^{n} w_{i} \mathbf{P}_{i} B_{i}^{n}(t)}{\sum_{i=0}^{n} w_{i} B_{i}^{n}(t)} \tag{20}
\end{equation*}
\]

\[
\begin{aligned}
& d(t)=\sum_{i=0}^{n} d_{i} B_{i}^{n}(t) \\
& d_{i}=w_{i}\left(a x_{i}+b y_{i}+c\right)
\end{aligned}
\]

\[
\left[\begin{array}{ll}
x_{1}-x_{0} & x_{n-1}-x_{n}  \tag{21}\\
y_{0}-y_{1} & y_{n}-y_{n-1}
\end{array}\right]\left\{\begin{array}{l}
c_{0} \\
c_{1}
\end{array}\right\}=\left\{\begin{array}{l}
y_{n}-y_{0} \\
x_{n}-x_{0}
\end{array}\right\}
\]

\[
\begin{equation*}
d(t)=\mathbf{P}^{\prime}(t) \cdot(\mathbf{P}(t)-\mathbf{F})=0 \tag{22}
\end{equation*}
\]

\[
\begin{equation*}
d_{i}=\sum_{\substack{i+k=i \\ j \in\{0, \ldots, n\} \\ k \in\{0, \ldots, n-1\}}} \frac{\binom{n}{j}\binom{n-1}{k}}{\binom{2 n-1}{i}} n\left(\mathbf{P}_{k+1}-\mathbf{P}_{k}\right) \cdot\left(\mathbf{P}_{j}-\mathbf{F}\right) \tag{23}
\end{equation*}
\]

\[
\begin{equation*}
D(t, u)=\left(\mathbf{P}(t)-\mathbf{F}_{\mathbf{Q}}(u)\right) \cdot \frac{\mathbf{P}^{\prime}(t)}{n} \neq 0,0 \leqslant u \leqslant 1 \tag{24}
\end{equation*}
\]

\[
\begin{equation*}
d(t, \dot{u})=\sum_{i=0}^{2 n-1} \sum_{j=0}^{m} B_{i}^{2 n-1}(t) B_{j}^{m}(u) d_{i j} \tag{25}
\end{equation*}
\]

\[
\begin{equation*}
d_{i j}=\sum_{\substack{k+1=i \\ 1 \in\{0, \ldots, n\} \\ k \in\{0, \ldots, n-1\}}} \frac{\binom{n}{j}\binom{n-1}{k}}{\binom{2 n-1}{j}} n\left(\mathbf{P}_{k+1}-\mathbf{P}_{k}\right) \cdot\left(\mathbf{P}_{l}-\mathbf{F}_{j}\right) \tag{26}
\end{equation*}
\]

\[
\begin{align*}
\mathbf{D}(t, u) & =\sum_{i=0}^{2 n-1} \sum_{i=0}^{m} B_{i}^{2 n-1}(t) B_{j}^{m}(u) \mathrm{D}_{i j} \\
& =(t, u, d(t, u)) \tag{27}
\end{align*}
\]

